import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"About Us - OpenCodeDocs","description":"Learn about OpenCodeDocs, the #1 AI ecosystem tutorial site providing source-driven, 100% runnable tutorials with verified examples.","frontmatter":{"title":"About Us - OpenCodeDocs","sidebarTitle":"About","subtitle":"About OpenCodeDocs","description":"Learn about OpenCodeDocs, the #1 AI ecosystem tutorial site providing source-driven, 100% runnable tutorials with verified examples."},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),i={name:"about.md"};function n(s,e,c,l,u,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="about-opencodedocs" tabindex="-1">About OpenCodeDocs <a class="header-anchor" href="#about-opencodedocs" aria-label="Permalink to &quot;About OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>#1 AI Ecosystem Tutorial Site · Source-Driven · 100% Runnable</strong></p></blockquote><h2 id="our-vision" tabindex="-1">Our Vision <a class="header-anchor" href="#our-vision" aria-label="Permalink to &quot;Our Vision&quot;">​</a></h2><p>AI tools are iterating rapidly, official documentation lags behind, and online tutorials are outdated—we are here to change that.</p><p>OpenCodeDocs deeply analyzes open-source project source code and official examples to extract core logic, ensuring every line of code runs through automated verification.</p><p>When a project updates, our tutorials update synchronously. Each tutorial is clearly marked with the Git Commit version, so you know exactly which version the code is based on.</p><p><strong>Our goal is to become the &quot;Verified Standard&quot; in the AI tool community.</strong></p><h2 id="open-source-license" tabindex="-1">Open Source License <a class="header-anchor" href="#open-source-license" aria-label="Permalink to &quot;Open Source License&quot;">​</a></h2><p>We believe openness brings trust. Contributions, corrections, and additions from the community are welcome.</p><h3 id="tutorial-content" tabindex="-1">Tutorial Content <a class="header-anchor" href="#tutorial-content" aria-label="Permalink to &quot;Tutorial Content&quot;">​</a></h3><p><strong>License</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> Attribution - NonCommercial - ShareAlike. You are free to share and adapt the material, but you must give appropriate credit, not use the material for commercial purposes, and distribute your contributions under the same license.</p><h3 id="build-tool" tabindex="-1">Build Tool <a class="header-anchor" href="#build-tool" aria-label="Permalink to &quot;Build Tool&quot;">​</a></h3><p><strong>VitePress</strong>: This project is built using <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>.<br> Special thanks to the VitePress team for providing such an excellent static site generator.</p><h2 id="contact-us" tabindex="-1">Contact Us <a class="header-anchor" href="#contact-us" aria-label="Permalink to &quot;Contact Us&quot;">​</a></h2><ul><li><strong>Email</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',15)])])}const b=t(i,[["render",n]]);export{p as __pageData,b as default};
